const items = $input.all();

return items.map(item => {
  const originalDate = item.json.body.data_e_hora;

  // Mantém apenas o formato YYYY-MM-DD
  const somenteData = originalDate.split('T')[0];

  return {
    json: {
      data_e_hora_formatada: somenteData,
      webhook_data: item.json.body
    }
  };
});

// Pega os dados do Merge (agendas + data processada)
const items = $input.all();

// Busca a data formatada (pode vir de qualquer item do merge)
const dataItem = items.find(item => item.json.data_e_hora_formatada);
if (!dataItem) {
    return [{ json: { erro: 'Data formatada não encontrada' } }];
}

const webhookData = dataItem.json.webhook_data || {};

// Verifica a data ORIGINAL do webhook (antes de adicionar timezone)
const dataOriginal = webhookData.data_e_hora;

// Verifica se a data original contém horário
// Com horário: "2025-07-08T14:30:00" ou "2025-07-08 14:30:00"
// Só data: "2025-07-08"
const temHorario = /T\d{2}:\d{2}|\s\d{2}:\d{2}/.test(dataOriginal);

if (temHorario) {
    // Data + Hora = busca direta
    return [{ json: { resultado: "busca_direta" } }];
} else {
    // Apenas Data = busca aberta  
    return [{ json: { resultado: "busca_aberta" } }];
}

const agora = new Date();

const horaSp = agora.getHours();
const diaSemana = agora.getDay(); // 0 = domingo, 6 = sábado

let resultado;

// Se hoje é sábado ou domingo → pular para segunda
if (diaSemana === 6 || diaSemana === 0) {
  resultado = 'segunda-feira';
} 
// Se sexta-feira depois das 17h → pular para segunda
else if (diaSemana === 5 && horaSp >= 17) {
  resultado = 'segunda-feira';
} 
// Segunda a quinta, depois das 17h → amanhã
else if (horaSp >= 17) {
  resultado = 'amanhã';
} 
// Segunda a sexta antes das 17h → hoje
else {
  resultado = 'hoje';
}

return [{
  json: {
    resultado,
    horaSaoPaulo: horaSp + 'h',
    dataFormatada: agora.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })
  }
}];

// Função para criar data de forma segura
function criarDataSegura(dataString) {
    // Se já é uma data completa ISO
    if (dataString.includes('T') || dataString.includes('Z')) {
        return new Date(dataString);
    }

    // Se é apenas uma data (YYYY-MM-DD), adiciona horário neutro
    if (dataString.match(/^\d{4}-\d{2}-\d{2}$/)) {
        return new Date(dataString + 'T12:00:00-03:00');
    }

    // Fallback
    return new Date(dataString);
}

// Pega a data de entrada
const dataEntrada = $('Webhook2').first().json.body.data_e_hora;
const entrada = criarDataSegura(dataEntrada);

// Acesso à agenda
let agendaDados;
try {
    agendaDados = $('agenda_isis').first().json;
} catch (error) {
    console.log('Erro ao acessar agenda_isis:', error);
    agendaDados = null;
}

// Função para adicionar dias úteis
function adicionarDiasUteis(data, diasUteis) {
    const resultado = new Date(data);
    let diasAdicionados = 0;

    while (diasAdicionados < diasUteis) {
        resultado.setDate(resultado.getDate() + 1);

        // Se não for fim de semana (0=domingo, 6=sábado), conta como dia útil
        if (resultado.getDay() !== 0 && resultado.getDay() !== 6) {
            diasAdicionados++;
        }
    }

    return resultado;
}

// Função para buscar horários na agenda
function buscarHorarios(agenda, diaSemana) {
    const diasSemana = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];
    const nomeDia = diasSemana[diaSemana];

    if (agenda && agenda[nomeDia] && agenda[nomeDia] !== 'não' && agenda[nomeDia].includes(' as ')) {
        const horarioString = agenda[nomeDia];
        const [inicio, fim] = horarioString.split(' as ');
        return {
            inicio: inicio.trim() + ':00',
            fim: fim.trim() + ':00'
        };
    }

    // Fallback padrão
    return {
        inicio: '08:00:00',
        fim: '17:00:00'
    };
}

// Calcula os próximos 3 dias úteis (incluindo o próprio dia se for útil)
const resultado = [];
let diasColetados = 0;

// Verifica se o próprio dia é útil
const diaEntrada = entrada.getDay();
const isProprioIdiaUtil = diaEntrada >= 1 && diaEntrada <= 5; // Segunda a sexta

// Se o próprio dia é útil, inclui ele primeiro
if (isProprioIdiaUtil) {
    const diaSemanaNumero = entrada.getDay();
    const horarios = buscarHorarios(agendaDados, diaSemanaNumero);

    const dataBase = entrada.toISOString().split('T')[0];
    const proximaDataInicio = dataBase + 'T' + horarios.inicio + '-03:00';
    const proximaDataFim = dataBase + 'T' + horarios.fim + '-03:00';
    const diaSemanaFinal = entrada.toLocaleDateString('pt-BR', { weekday: 'long' });

    resultado.push({
        json: {
            data_original: entrada.toISOString(),
            dia_original: entrada.toLocaleDateString('pt-BR', { weekday: 'long' }),
            proxima_data_inicio: proximaDataInicio,
            proxima_data_fim: proximaDataFim,
            proximo_dia_semana: diaSemanaFinal,
            dia_util_numero: 1,
            debug_data_entrada: dataEntrada,
            debug_proprio_dia: true
        }
    });

    diasColetados = 1;
}

// Agora adiciona os próximos dias úteis até completar 3
let diasParaAdicionar = 1;
while (diasColetados < 3) {
    const proximaData = adicionarDiasUteis(entrada, diasParaAdicionar);
    const diaSemanaNumero = proximaData.getDay();

    // Busca horários na agenda para este dia da semana
    const horarios = buscarHorarios(agendaDados, diaSemanaNumero);

    // Formata a data no timezone de São Paulo
    const dataBase = proximaData.toISOString().split('T')[0];
    const proximaDataInicio = dataBase + 'T' + horarios.inicio + '-03:00';
    const proximaDataFim = dataBase + 'T' + horarios.fim + '-03:00';
    const diaSemanaFinal = proximaData.toLocaleDateString('pt-BR', { weekday: 'long' });

    resultado.push({
        json: {
            data_original: entrada.toISOString(),
            dia_original: entrada.toLocaleDateString('pt-BR', { weekday: 'long' }),
            proxima_data_inicio: proximaDataInicio,
            proxima_data_fim: proximaDataFim,
            proximo_dia_semana: diaSemanaFinal,
            dia_util_numero: diasColetados + 1,
            debug_data_entrada: dataEntrada,
            debug_proprio_dia: false
        }
    });

    diasColetados++;
    diasParaAdicionar++;
}

return resultado;

