// Extrai a parte de hora e minuto manualmente
const [dataParte, horaParte] = originalString.split('T');
const [hora, minuto] = horaParte.split(':');

// Função para adicionar dias úteis
function adicionarDiasUteis(data, diasUteis) {
  const resultado = new Date(data);
  let diasAdicionados = 0;

  while (diasAdicionados < diasUteis) {
    resultado.setDate(resultado.getDate() + 1);

    // Se não for fim de semana (0=domingo, 6=sábado), conta como dia útil
    if (resultado.getDay() !== 0 && resultado.getDay() !== 6) {
      diasAdicionados++;
    }
  }

  return resultado;
}

// Função para formatar data mantendo hora original
function formatarData(data, hora, minuto) {
  const pad = (n) => n.toString().padStart(2, '0');
  const ano = data.getFullYear();
  const mes = pad(data.getMonth() + 1);
  const dia = pad(data.getDate());
  return `${ano}-${mes}-${dia}T${hora}:${minuto}:00-03:00`;
}

// Cria data original como objeto Date
const dataOriginal = new Date(originalString);

// Calcula os próximos 3 dias úteis e retorna como 3 itens separados
const resultado = [];

for (let i = 1; i <= 3; i++) {
  const proximaData = adicionarDiasUteis(dataOriginal, i);
  const dataFormatada = formatarData(proximaData, hora, minuto);
  const diaSemana = proximaData.toLocaleDateString('pt-BR', { weekday: 'long' });

  resultado.push({
    json: {
      data_original: originalString,
      proxima_data_com_mesma_hora: dataFormatada,
      proximo_dia_semana: diaSemana,
      dia_util_numero: i
    }
  });
}

// Retorna 3 itens separados
return resultado;

