// ====== CODE89 - ESPECÍFICO PARA ARTHUR ======

// Função para gerar horários baseado no funcionamento da agenda_arthur
function gerarHorariosBase(diaSemana) {
  const agendaArthur = $('agenda_arthur').first().json;

  if (!agendaArthur || !agendaArthur[diaSemana] || agendaArthur[diaSemana] === 'não') {
    return []; // Dia não trabalha
  }

  const horarioString = agendaArthur[diaSemana]; // ex: "09:00 as 18:00"

  if (!horarioString.includes(' as ')) {
    throw new Error(`Formato de horário inválido para ${diaSemana}: ${horarioString}`);
  }

  const [inicio, fim] = horarioString.split(' as ');
  const [inicioH] = inicio.trim().split(':').map(Number);
  const [fimH] = fim.trim().split(':').map(Number);

  const horarios = [];

  // Gera horários de hora em hora
  for (let hora = inicioH; hora < fimH; hora++) {
    // Pula horário de almoço (12:00-13:00)
    if (hora === 12 && inicioH < 12 && fimH > 13) {
      continue;
    }

    horarios.push(`${hora.toString().padStart(2, '0')}:00`);
  }

  return horarios;
}

// Função para obter horários de funcionamento da agenda_arthur
function obterHorariosFuncionamento(diaSemana) {
  const agendaArthur = $('agenda_arthur').first().json;

  if (!agendaArthur || !agendaArthur[diaSemana] || agendaArthur[diaSemana] === 'não') {
    throw new Error(`Dia ${diaSemana} não tem horário definido na agenda_arthur`);
  }

  const horarioTrabalho = agendaArthur[diaSemana];

  if (!horarioTrabalho.includes(' as ')) {
    throw new Error(`Formato inválido para ${diaSemana}: ${horarioTrabalho}`);
  }

