const [datePart, timePartWithTZ] = isoString.split('T');
const [horaStr] = timePartWithTZ.split(':');
const horaConsulta = parseInt(horaStr, 10);

// Extrai o dia da semana
const [ano, mes, dia] = datePart.split('-').map(Number);
const dataConsulta = new Date(ano, mes - 1, dia);
const diaSemana = dataConsulta.toLocaleDateString('pt-BR', { weekday: 'long' }).toLowerCase();

// Pega e parseia as agendas
const raw = items[0].json.agendas;
let agendas;
try {
  agendas = JSON.parse(raw);
} catch (e) {
  return [{ json: { erro: 'Erro ao fazer parse das agendas' } }];
}

// Função para verificar se horário está dentro da faixa
function horarioDentroDaFaixa(faixa, hora) {
  if (!faixa || faixa.toLowerCase() === 'não') return false;

  const [inicioStr, fimStr] = faixa.split(' as ');
  const inicio = parseInt(inicioStr.split(':')[0], 10);
  const fim = parseInt(fimStr.split(':')[0], 10);

  return hora >= inicio && hora < fim;
}

// Verifica quais agendas estão disponíveis
const disponiveis = agendas
  .filter(item => {
    const faixa = item.json[diaSemana];
    return horarioDentroDaFaixa(faixa, horaConsulta);
  })
  .map(item => item.json.agenda);

let resultado;
if (disponiveis.length === 2) {
  resultado = 'Ambos';
} else if (disponiveis.length === 1) {
  resultado = disponiveis[0];
} else {
  resultado = 'Nenhum';
}

return [
  {
    json: {
      dia_semana: diaSemana,
      hora_consulta: horaConsulta,
      resultado
    }
  }
];

// Pega todos os dias processados
const todosOsDias = $input.all();

// Pega as agendas e informações da consulta original
const agendasRaw = $('Edit Fields28').first().json.agendas;
const agendas = JSON.parse(agendasRaw);
const agendaOriginal = $('Code88').first().json.resultado;
const horaConsulta = $('Code88').first().json.hora_consulta;

// Função para verificar se horário está na faixa
function horarioDentroDaFaixa(faixa, hora) {
  if (!faixa || faixa.toLowerCase() === 'não') return false;

  const [inicioStr, fimStr] = faixa.split(' as ');
  const inicio = parseInt(inicioStr.split(':')[0], 10);
  const fim = parseInt(fimStr.split(':')[0], 10);

  return hora >= inicio && hora < fim;
}

// Função para verificar se agenda permite o horário em determinado dia
function agendaPermiteDia(diaSemana) {
  if (agendaOriginal === 'Arthur') {
    const agendaArthur = agendas.find(a => a.json.agenda === 'Arthur');
    return horarioDentroDaFaixa(agendaArthur.json[diaSemana], horaConsulta);

  } else if (agendaOriginal === 'Isis') {
    const agendaIsis = agendas.find(a => a.json.agenda === 'Isis');
    return horarioDentroDaFaixa(agendaIsis.json[diaSemana], horaConsulta);

  } else if (agendaOriginal === 'Ambos') {
    const agendaArthur = agendas.find(a => a.json.agenda === 'Arthur');
    const agendaIsis = agendas.find(a => a.json.agenda === 'Isis');

    const arthurPermite = horarioDentroDaFaixa(agendaArthur.json[diaSemana], horaConsulta);
    const isisPermite = horarioDentroDaFaixa(agendaIsis.json[diaSemana], horaConsulta);

    return arthurPermite || isisPermite;
  }
  return false;
}

// Filtra apenas os dias que estão disponíveis E a agenda permite
const diasDisponiveis = todosOsDias
  .map(item => {
    const dia = Object.keys(item.json)[0];
    const calendarDisponivel = item.json[dia];
    const agendaPermite = agendaPermiteDia(dia);

    // Só inclui se AMBOS forem true
    return (calendarDisponivel && agendaPermite) ? dia : null;
  })
  .filter(dia => dia !== null);

// Pega a data original do webhook
const dataOriginal = $('Webhook2').first().json.body.data_e_hora;
const data = new Date(dataOriginal);
const diaSemanaOriginal = data.toLocaleDateString('pt-BR', { weekday: 'long' });
const dataFormatada = data.toLocaleDateString('pt-BR');

// Monta a mensagem final
if (diasDisponiveis.length === 0) {
  return [{
    json: {
      mensagem: `Infelizmente para ${diaSemanaOriginal} (${dataFormatada}) não temos esse horário disponível, e nos próximos dias úteis também não temos disponibilidade no mesmo horário.`
    }
  }];
}

const diasTexto = diasDisponiveis.join(', ').replace(/, ([^,]*)$/, ' e $1');
const mensagem = `Infelizmente para ${diaSemanaOriginal} (${dataFormatada}) não temos esse horário, porém temos ${diasTexto} no mesmo horário, o que acha?`;

return [{
  json: {
    mensagem,
    dias_disponiveis: diasDisponiveis
  }
}];

const items = $input.all();

// Junta os campos dias_disponiveis
const diasUnicos = new Set();
let mensagemPadrao = null;

for (const item of items) {
  const dias = item.json.dias_disponiveis;

  if (dias && Array.isArray(dias)) {
    dias.forEach(dia => diasUnicos.add(dia));
  } else {
    // guarda a mensagem final caso não haja dias disponíveis
    mensagemPadrao = item.json.mensagem;
  }
}

// Constrói a nova mensagem
let novaMensagem;
const diasArray = Array.from(diasUnicos);

if (diasArray.length > 0) {
  const diasTexto = diasArray.join(', ').replace(/, ([^,]*)$/, ' e $1');
  novaMensagem = `Infelizmente para essa data não temos esse horário, porém temos ${diasTexto} no mesmo horário, o que acha?`;
} else {
  novaMensagem = mensagemPadrao;
}

// Retorna como array de item
return [
  {
    json: {
      mensagem_final: novaMensagem
    }
  }
];

// Pega todos os dias processados
const todosOsDias = $input.all();

// Pega as agendas e informações da consulta original
const agendasRaw = $('Edit Fields28').first().json.agendas;
const agendas = JSON.parse(agendasRaw);
const agendaOriginal = $('Code88').first().json.resultado;
const horaConsulta = $('Code88').first().json.hora_consulta;

// Função para verificar se horário está na faixa
function horarioDentroDaFaixa(faixa, hora) {
  if (!faixa || faixa.toLowerCase() === 'não') return false;

  const [inicioStr, fimStr] = faixa.split(' as ');
  const inicio = parseInt(inicioStr.split(':')[0], 10);
  const fim = parseInt(fimStr.split(':')[0], 10);

  return hora >= inicio && hora < fim;
}

// Função para verificar se agenda permite o horário em determinado dia
function agendaPermiteDia(diaSemana) {
  if (agendaOriginal === 'Arthur') {
    const agendaArthur = agendas.find(a => a.json.agenda === 'Arthur');
    return horarioDentroDaFaixa(agendaArthur.json[diaSemana], horaConsulta);

  } else if (agendaOriginal === 'Isis') {
    const agendaIsis = agendas.find(a => a.json.agenda === 'Isis');
    return horarioDentroDaFaixa(agendaIsis.json[diaSemana], horaConsulta);

  } else if (agendaOriginal === 'Ambos') {
    const agendaArthur = agendas.find(a => a.json.agenda === 'Arthur');
    const agendaIsis = agendas.find(a => a.json.agenda === 'Isis');

    const arthurPermite = horarioDentroDaFaixa(agendaArthur.json[diaSemana], horaConsulta);
    const isisPermite = horarioDentroDaFaixa(agendaIsis.json[diaSemana], horaConsulta);

    return arthurPermite || isisPermite;
  }
  return false;
}

// Filtra apenas os dias que estão disponíveis E a agenda permite
const diasDisponiveis = todosOsDias
  .map(item => {
    const dia = Object.keys(item.json)[0];
    const calendarDisponivel = item.json[dia];
    const agendaPermite = agendaPermiteDia(dia);

    // Só inclui se AMBOS forem true
    return (calendarDisponivel && agendaPermite) ? dia : null;
  })
  .filter(dia => dia !== null);

// Pega a data original do webhook
const dataOriginal = $('Webhook2').first().json.body.data_e_hora;
const data = new Date(dataOriginal);
const diaSemanaOriginal = data.toLocaleDateString('pt-BR', { weekday: 'long' });
const dataFormatada = data.toLocaleDateString('pt-BR');

// Monta a mensagem final
if (diasDisponiveis.length === 0) {
  return [{
    json: {
      mensagem: `Infelizmente para ${diaSemanaOriginal} (${dataFormatada}) não temos esse horário disponível, e nos próximos dias úteis também não temos disponibilidade no mesmo horário.`
    }
  }];
}

const diasTexto = diasDisponiveis.join(', ').replace(/, ([^,]*)$/, ' e $1');
const mensagem = `Infelizmente para ${diaSemanaOriginal} (${dataFormatada}) não temos esse horário, porém temos ${diasTexto} no mesmo horário, o que acha?`;

return [{
  json: {
    mensagem,
    dias_disponiveis: diasDisponiveis
  }
}];

const items = $input.all();

// Junta os campos dias_disponiveis
const diasUnicos = new Set();
let mensagemPadrao = null;

for (const item of items) {
  const dias = item.json.dias_disponiveis;

  if (dias && Array.isArray(dias)) {
    dias.forEach(dia => diasUnicos.add(dia));
  } else {
    // guarda a mensagem final caso não haja dias disponíveis
    mensagemPadrao = item.json.mensagem;
  }
}

// Constrói a nova mensagem
let novaMensagem;
const diasArray = Array.from(diasUnicos);

if (diasArray.length > 0) {
  const diasTexto = diasArray.join(', ').replace(/, ([^,]*)$/, ' e $1');
  novaMensagem = `Infelizmente para essa data não temos esse horário, porém temos ${diasTexto} no mesmo horário, o que acha?`;
} else {
  novaMensagem = mensagemPadrao;
}

// Retorna como array de item
return [
  {
    json: {
      mensagem_final: novaMensagem
    }
  }
];

// ====== CODE89 - ESPECÍFICO PARA ARTHUR ======

// Função para gerar horários baseado no funcionamento da agenda_arthur
function gerarHorariosBase(diaSemana) {
  const agendaArthur = $('agenda_arthur').first().json;

  if (!agendaArthur || !agendaArthur[diaSemana] || agendaArthur[diaSemana] === 'não') {
    return []; // Dia não trabalha
  }

  const horarioString = agendaArthur[diaSemana]; // ex: "09:00 as 18:00"

  if (!horarioString.includes(' as ')) {
    throw new Error(`Formato de horário inválido para ${diaSemana}: ${horarioString}`);
  }

  const [inicio, fim] = horarioString.split(' as ');
  const [inicioH] = inicio.trim().split(':').map(Number);
  const [fimH] = fim.trim().split(':').map(Number);

  const horarios = [];

  // Gera horários de hora em hora
  for (let hora = inicioH; hora < fimH; hora++) {
    // Pula horário de almoço (12:00-13:00)
    if (hora === 12 && inicioH < 12 && fimH > 13) {
      continue;
    }

    horarios.push(`${hora.toString().padStart(2, '0')}:00`);
  }

  return horarios;
}

// Função para obter horários de funcionamento da agenda_arthur
function obterHorariosFuncionamento(diaSemana) {
  const agendaArthur = $('agenda_arthur').first().json;

  if (!agendaArthur || !agendaArthur[diaSemana] || agendaArthur[diaSemana] === 'não') {
    throw new Error(`Dia ${diaSemana} não tem horário definido na agenda_arthur`);
  }

  const horarioTrabalho = agendaArthur[diaSemana];

  if (!horarioTrabalho.includes(' as ')) {
    throw new Error(`Formato inválido para ${diaSemana}: ${horarioTrabalho}`);
  }

  const [inicio, fim] = horarioTrabalho.split(' as ');
  return {
    inicio: inicio.trim(),
    fim: fim.trim()
  };
}

// Função para verificar se um horário está ocupado
function horarioEstaOcupado(horario, eventosString, dataRef) {
  if (!eventosString || eventosString === "[]" || eventosString === "") {
    return false;
  }
  const eventos = JSON.parse(eventosString);
  const horarioTarget = new Date(`${dataRef}T${horario}:00-03:00`);
  return eventos.some(evento => {
    const inicio = new Date(evento.start);
    const fim = new Date(evento.end);
    return horarioTarget >= inicio && horarioTarget < fim;
  });
}

// ====== EXECUÇÃO PRINCIPAL ======
const inputData = $input.all();
const diasDisponiveis = [];

for (const item of inputData) {
  const { dia_semana, data_referencia } = item.json;
  const eventos = item.json[dia_semana];
  const horariosFuncionamento = obterHorariosFuncionamento(dia_semana);

  // Horários dinâmicos baseados na agenda_arthur
  const horariosBase = gerarHorariosBase(dia_semana);

  // Retorna TODOS os horários livres
  const horariosLivres = horariosBase.filter(horario => {
    const [horaH, minH] = horario.split(':').map(Number);
    const [inicioH, inicioM] = horariosFuncionamento.inicio.split(':').map(Number);
    const [fimH, fimM] = horariosFuncionamento.fim.split(':').map(Number);

    const horarioMinutos = horaH * 60 + minH;
    const inicioMinutos = inicioH * 60 + inicioM;
    const fimMinutos = fimH * 60 + fimM;

    const dentroFuncionamento = horarioMinutos >= inicioMinutos && horarioMinutos <= fimMinutos;
    const naoOcupado = !horarioEstaOcupado(horario, eventos, data_referencia);

    return dentroFuncionamento && naoOcupado;
  });

  // Inclui o dia com TODOS os horários livres
  if (horariosLivres.length > 0) {
    // Formata a data de YYYY-MM-DD para DD/MM/YYYY
    const [ano, mes, dia] = data_referencia.split('-');
    const dataFormatada = `${dia}/${mes}/${ano}`;

    diasDisponiveis.push({
      dia: dia_semana,
      data: dataFormatada,
      data_referencia: data_referencia, // Mantém formato original também
      horarios: horariosLivres.sort()
    });
  }
}

// Monta a mensagem final
let mensagem;
if (diasDisponiveis.length === 0) {
  mensagem = "Não há horários disponíveis nesta agenda no momento.";
} else {
  const opcoes = diasDisponiveis.map(item =>
