parameters.jsCode:
const items = $input.all();

const horariosPorDia = {};

for (const item of items) {
  const texto = item.json.response;

  // REGEX ATUALIZADO: captura dia da semana, data E horários
  // Formato: "segunda-feira (21/07/2025): 09:00, 10:00, 11:00"
  const regexGeral = /([^\s:|]+-feira)\s*\(([^)]+)\)\s*:\s*([\d:, ]+)/gi;
  const matches = texto.matchAll(regexGeral);

  for (const match of matches) {
    const dia = match[1].toLowerCase();
    const data = match[2]; // NOVO: captura a data
    const horariosStr = match[3];

    // Usa dia+data como chave única para evitar sobreposição
    const chaveUnica = `${dia}_${data}`;

    if (!horariosPorDia[chaveUnica]) {
      horariosPorDia[chaveUnica] = {
        dia: dia,
        data: data, // NOVO: inclui a data
        horarios: new Set()
      };
    }

    const horarios = horariosStr
      .replace(/O que acha\?/gi, '')
      .replace(/\./g, '')
      .split(',')
      .map(h => h.trim())
      .filter(Boolean);

    horarios.forEach(h => horariosPorDia[chaveUnica].horarios.add(h));
  }
}

// Resultado final
const resultado = Object.values(horariosPorDia)
  .map(item => ({
    dia: item.dia,
    data: item.data, // NOVO: inclui a data no resultado
    horarios: Array.from(item.horarios).sort()
  }));

return [{ json: { horarios_disponiveis: resultado } }];
